starter_code:
#include <stdio.h>
#include <stddef.h>

struct Padded {
    char a;
    int b;
    char c;
};

struct Packed {
    int x;
    int y;
};

int main(void) {
    printf("char: %zu\n", sizeof(char));
    printf("int: %zu\n", sizeof(int));
    printf("long: %zu\n", sizeof(long));
    printf("ptr: %zu\n", sizeof(void *));
    printf("Padded size: %zu\n", ____(struct Padded));
    printf("Packed size: %zu\n", sizeof(struct Packed));
    printf("offsetof(Padded, b): %zu\n", ____(struct Padded, b));
    printf("offsetof(Padded, c): %zu\n", offsetof(struct Padded, c));
    printf("Padding exists: %s\n",
        sizeof(struct Padded) > sizeof(char) + sizeof(int) + sizeof(char) ? "yes" : "no");
    return 0;
}

